VALUES
  ('police-8b7f1efc-moex-00647', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '從美國回臺灣定居的甲，隻身外出旅遊，騎著新買的機車就上路了。但巡邏員警見其一路東張西 望，便將其攔下，請其出示身分證。但甲表示未帶身分證，懷疑其為通緝犯，遂直接強拉其上車， 帶回警局查證。請問警員此舉，依照司法院釋字第535號解釋之意旨，違背下列那個原則？', '["罪疑惟輕原則", "無罪推定原則", "比例原則", "依法行政原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00648', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '下列何者不屬於傳聞證據？', '["被害人警詢筆錄", "被告警詢筆錄", "車禍現場圖", "搜索筆錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00649', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警官甲帶隊持搜索票前往乙宅執行搜索，案由是違反槍砲彈藥刀械管制條例。乙宅位於某大樓的 5樓，進入乙宅後，歷經3個小時，一無所獲。但意外發現乙前陣子買下6樓，裝潢即將完成， 甲表示「參觀一下嘛！我也想買這個社區的房子耶！」，乙表示「不方便」，但整隊人馬已經上樓 並趁大門未上鎖，便直接進入「參觀」。果然在衣櫃抽屜發現兩把制式手槍、20 發子彈，遂全部 予以扣押。請問：上述所扣押之槍彈，有無證據能力？', '["因為所扣押之槍彈屬於違禁物品，故有絕對之證據能力", "因為5樓、6樓皆為乙所有之住宅，原搜索票效力仍及於6樓，故其所扣押之物仍有證據能力", "因為搜索票僅記載5樓，且乙並無出於自願性之同意，屬於違背法定程序之搜索，其證據能力 之有無應由法院權衡之", "因為甲佯稱「參觀」實為「搜索」，屬於不正方法所取得之證據，故無證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00650', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '檢察官將被告警詢時之自白（筆錄）提出於法院證明被告有罪，但被告抗辯該自白係出於刑求， 請問法院依法應如何調查？', '["法院以自由心證判斷是否可信，無須另為調查", "應優先調查，並由檢察官證明該自白係出於自由意志", "此顯已構成爭點，宜留待證據調查程序之最後再朗讀內容調查之", "法院應立即命被告提出其遭刑求之證據以證明之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00651', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '當事人向法院聲請調查之證據，法院若認為不必要者，得駁回聲請。所謂「不必要」，不包含下列 何種情形？', '["該證據顯然不具證明力者", "與待證事實無重要關係者", "待證事實已明確而無須再調查者", "該證據事實上已不能調查者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00652', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '偵辦網路犯罪案件，在執行電腦搜索、扣押時，下列那一項作為不妥？', '["應使被搜索人與電腦保持適當距離，避免刪除檔案或證據", "得安裝適當程式至被搜索人之電腦，使證據蒐集較為快速", "電腦檔案之證據應當場列印，並請被搜索人簽名捺印", "扣押整套電腦設備（主機、螢幕、鍵盤、電源線等）為宜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00653', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '對於證人之詢問，下列注意事項何者錯誤？', '["證人之通知書應一律以書面送達，不得以電話、傳真或口頭為之", "若該證人與嫌疑人有三親等內血親之關係者，應告知得拒絕證言", "應注意該證人是否有依「證人保護法」保護之必要", "經以證人通知受詢問者，若認為有犯罪嫌疑，應告知相關權利並得其同意後，就犯罪事實重為 詢問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00654', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警察偵辦某竊盜案件，發現贓物之中除一般財物之外，還有一部挖土機，若無被害人報案，請問 該挖土機該如何扣押較為妥當？', '["仍應先隨案移送至地檢署，再由檢察官決定是否移至他處保管", "大型贓證物以拍照存證並於搜索筆錄載明即可", "應交與適當之第三人保管，並將保管單隨案移送", "應請適當之第三人收購後，以該價金為扣押物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00655', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '下列關於組織犯罪認定與偵辦之敘述，何者正確？', '["所謂「犯罪組織」以具有名稱、固定場所或分工明確等為必要", "犯罪組織也包括為了立即實施犯罪而隨意組成者", "偵辦此類案件，尤應注意其財產及不法利得的來源及流向", "若有檢舉人，其身分資料應妥善封存，並附入移送之文書內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00656', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-359207d9', 'sub-police-8b7f1efc-05', NULL, 'essay', '作文：（60分）
